/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Features:
 * - Formats notification payloads as JSON
 * - POSTs to a configured URL
 * - Pluggable transport: swap InMemoryWebhookTransport for a real HTTP client
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body sent to the webhook endpoint.
 */
export interface WebhookPayload {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/**
 * Transport abstraction for webhook delivery.
 * Implement this interface to plug in a real HTTP client (fetch, axios, etc.).
 */
export interface WebhookTransport {
  post(url: string, body: WebhookPayload): Promise<{ statusCode: number }>;
}

/**
 * A delivered webhook record, for auditing and testing.
 */
export interface DeliveredWebhook {
  url: string;
  payload: WebhookPayload;
  deliveredAt: Date;
  statusCode: number;
}

/**
 * In-memory webhook transport for development and testing.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private deliveries: Array<{ url: string; body: WebhookPayload }> = [];

  async post(url: string, body: WebhookPayload): Promise<{ statusCode: number }> {
    this.deliveries.push({ url, body });
    return { statusCode: 200 };
  }

  getDeliveries(): Array<{ url: string; body: WebhookPayload }> {
    return [...this.deliveries];
  }

  clearDeliveries(): void {
    this.deliveries = [];
  }
}

// --- WebhookAdapter ---

let nextId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounter(): void {
  nextId = 1;
}

export interface WebhookAdapterOptions {
  url: string;
  transport?: WebhookTransport;
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveredWebhooks: DeliveredWebhook[] = [];
  private url: string;
  private transport: WebhookTransport;

  constructor(options: WebhookAdapterOptions) {
    this.url = options.url;
    this.transport = options.transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Send a webhook notification:
   * 1. Format the notification payload as JSON
   * 2. POST to the configured URL via the transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const webhookId = generateWebhookId();

    const webhookPayload: WebhookPayload = {
      event: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };

    this.logger.info(`Sending webhook to ${this.url}: ${payload.type}`);

    try {
      const result = await this.transport.post(this.url, webhookPayload);

      if (result.statusCode >= 200 && result.statusCode < 300) {
        const delivered: DeliveredWebhook = {
          url: this.url,
          payload: webhookPayload,
          deliveredAt: new Date(),
          statusCode: result.statusCode,
        };

        this.deliveredWebhooks.push(delivered);

        return {
          success: true,
          notificationId: webhookId,
          channel: 'webhook',
        };
      }

      this.logger.error(`Webhook returned status ${result.statusCode}`);
      return {
        success: false,
        notificationId: webhookId,
        channel: 'webhook',
        error: `Webhook returned status ${result.statusCode}`,
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Transport error: ${message}`);
      return {
        success: false,
        notificationId: webhookId,
        channel: 'webhook',
        error: `Transport error: ${message}`,
      };
    }
  }

  /**
   * Get all delivered webhooks. Useful for testing.
   */
  getDeliveredWebhooks(): DeliveredWebhook[] {
    return [...this.deliveredWebhooks];
  }

  /**
   * Clear delivered webhooks. Useful for testing.
   */
  clearDeliveredWebhooks(): void {
    this.deliveredWebhooks = [];
  }
}

